const D = "2026-06-09";

function base(id, title, summary, sourceUrl, sourceType, confidence, sourceIds, extra = {}) {
  return {
    id,
    title,
    summary,
    tags: extra.tags ?? [],
    created_at: D,
    updated_at: D,
    reviewed_at: D,
    source_url: sourceUrl,
    source_type: sourceType,
    confidence_level: confidence,
    status: extra.status ?? "active",
    reviewer_notes: extra.reviewer_notes ?? "",
    source_ids: sourceIds,
    ...extra.fields,
  };
}

